// TinyURL Node.js Implementation

const redis = require('redis');
const pool = require('mysql2/promise');

class TinyURL {
  constructor(dbPool, redisClient) {
    this.db = dbPool;
    this.cache = redisClient;
    this.BASE62 = '0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ';
    this.CACHE_TTL = 86400; // 24 hours
  }

  encodeBase62(num) {
    if (num === 0) return this.BASE62[0];
    const digits = [];
    while (num > 0) {
      digits.push(this.BASE62[num % 62]);
      num = Math.floor(num / 62);
    }
    return digits.reverse().join('');
  }

  async shorten(longUrl, customCode = null) {
    if (customCode) {
      // Check collision in cache and DB
      const exists = await this.cache.get(`url:${customCode}`);
      if (exists) throw new Error('Custom code already taken');
      const [rows] = await this.db.query(
        'SELECT id FROM urls WHERE short_url = ?',
        [customCode]
      );
      if (rows.length > 0) throw new Error('Custom code already taken');
      var shortCode = customCode;
    } else {
      // Insert URL and encode ID
      const [result] = await this.db.query(
        'INSERT INTO urls (long_url) VALUES (?)',
        [longUrl]
      );
      shortCode = this.encodeBase62(result.insertId);
      // Update short_url column
      await this.db.query(
        'UPDATE urls SET short_url = ? WHERE id = ?',
        [shortCode, result.insertId]
      );
    }

    // Cache bidirectional mapping
    await this.cache.setEx(`url:${shortCode}`, this.CACHE_TTL, longUrl);
    await this.cache.setEx(`code:${longUrl}`, this.CACHE_TTL, shortCode);
    return shortCode;
  }

  async redirect(shortCode) {
    // Check cache first (hot path)
    const cached = await this.cache.get(`url:${shortCode}`);
    if (cached) {
      this.queueAnalytics(shortCode); // async, non-blocking
      return cached;
    }

    // Cache miss: query database
    const [rows] = await this.db.query(
      'SELECT long_url FROM urls WHERE short_url = ?',
      [shortCode]
    );
    if (rows.length === 0) return null;

    const longUrl = rows[0].long_url;
    // Update cache
    await this.cache.setEx(`url:${shortCode}`, this.CACHE_TTL, longUrl);

    // Async: increment click count
    this.queueAnalytics(shortCode);
    return longUrl;
  }

  async queueAnalytics(shortCode) {
    // Async queue to message broker (Kafka, RabbitMQ)
    // For production: queue to external message queue
    // For now: use Redis counter with periodic batch writes
    const key = `analytics:${shortCode}`;
    await this.cache.incr(key);
    // Batch write to DB periodically (every minute)
  }
}

module.exports = TinyURL;

// Pastebin Node.js Implementation

const redis = require('redis');
const pool = require('mysql2/promise');
const zlib = require('zlib');
const { v4: uuidv4 } = require('uuid');
const AWS = require('aws-sdk');

class Pastebin {
  constructor(dbPool, redisClient, s3Client) {
    this.db = dbPool;
    this.cache = redisClient;
    this.s3 = s3Client;
    this.CACHE_TTL = 86400; // 24 hours
    this.HOT_TIER_DAYS = 30;
  }

  async createPaste(content, language, {
    title = null,
    expiresHours = null,
    visibility = 'PUBLIC',
    userId = null
  } = {}) {
    // Compress content
    const compressed = zlib.gzipSync(content);
    const contentToStore = compressed.length < Buffer.byteLength(content) 
      ? { data: compressed, isCompressed: true }
      : { data: Buffer.from(content), isCompressed: false };

    // Generate unique short code
    const shortCode = await this._generateShortCode();

    // Calculate expiration
    let expiresAt = null;
    if (expiresHours) {
      expiresAt = new Date(Date.now() + expiresHours * 3600000);
    }

    // Store in DB
    const [result] = await this.db.query(
      `INSERT INTO pastes 
       (user_id, short_code, title, content, language, expires_at, visibility, is_compressed)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?)`,
      [userId, shortCode, title, contentToStore.data, language, expiresAt, visibility, contentToStore.isCompressed]
    );

    // Cache the paste
    const cacheData = JSON.stringify({
      content,
      language,
      title: title || '',
      visibility,
      viewCount: 0,
      createdAt: new Date().toISOString()
    });
    await this.cache.setEx(`paste:${shortCode}`, this.CACHE_TTL, cacheData);

    return shortCode;
  }

  async getPaste(shortCode, userId = null) {
    // Check cache first (hot path)
    const cached = await this.cache.get(`paste:${shortCode}`);
    if (cached) {
      const pasteData = JSON.parse(cached);
      // Check visibility
      if (!this._checkAccess(pasteData.visibility, userId)) {
        return null;
      }
      // Async increment view count
      this.cache.incr(`views:${shortCode}`).catch(console.error);
      return pasteData;
    }

    // Cache miss: fetch from DB
    const [rows] = await this.db.query(
      `SELECT id, content, language, title, visibility, is_compressed, view_count, created_at
       FROM pastes WHERE short_code = ?`,
      [shortCode]
    );

    if (rows.length === 0) return null;

    const { id, content, language, title, visibility, is_compressed, view_count, created_at } = rows[0];

    // Check visibility
    if (!this._checkAccess(visibility, userId)) {
      return null;
    }

    // Decompress if needed
    let decompressed = content;
    if (is_compressed) {
      decompressed = zlib.gunzipSync(content).toString();
    } else if (Buffer.isBuffer(content)) {
      decompressed = content.toString();
    }

    // Update cache
    const cacheData = JSON.stringify({
      content: decompressed,
      language,
      title: title || '',
      visibility,
      viewCount: view_count,
      createdAt: created_at.toISOString()
    });
    await this.cache.setEx(`paste:${shortCode}`, this.CACHE_TTL, cacheData);

    // Async view count increment
    this.cache.incr(`views:${shortCode}`).catch(console.error);

    return JSON.parse(cacheData);
  }

  async _generateShortCode() {
    let shortCode;
    let exists = true;

    while (exists) {
      // Generate 8-char random code
      shortCode = uuidv4().replace(/-/g, '').substring(0, 8);

      // Check collision
      const [rows] = await this.db.query(
        'SELECT id FROM pastes WHERE short_code = ?',
        [shortCode]
      );
      exists = rows.length > 0;
    }

    return shortCode;
  }

  _checkAccess(visibility, userId) {
    if (visibility === 'PUBLIC' || visibility === 'UNLISTED') {
      return true;  // Anyone with link
    }
    if (visibility === 'PRIVATE') {
      return userId !== null;  // Owner only
    }
    return false;
  }

  async archiveExpiredPastes() {
    """Move expired pastes to S3 and delete from DB. Run hourly."""
    const [rows] = await this.db.query(
      `SELECT id, short_code, content FROM pastes 
       WHERE expires_at < NOW() AND archived_at IS NULL
       LIMIT 1000`
    );

    for (const { id, short_code, content } of rows) {
      // Archive to S3
      const key = `pastes/archived/${short_code}.gz`;
      await this.s3.putObject({
        Bucket: 'pastebin-archive',
        Key: key,
        Body: content,
        ContentEncoding: 'gzip'
      }).promise();

      // Mark archived
      await this.db.query(
        'UPDATE pastes SET archived_at = NOW() WHERE id = ?',
        [id]
      );
      await this.cache.del(`paste:${short_code}`);
    }
  }
}

module.exports = Pastebin;

// Instagram Node.js Implementation

const redis = require('redis');
const pool = require('mysql2/promise');
const { Kafka } = require('kafkajs');

const NotificationType = {
  LIKE: 'like',
  COMMENT: 'comment',
  FOLLOW: 'follow',
  MENTION: 'mention'
};

class Instagram {
  constructor(dbPool, redisClient, kafka) {
    this.db = dbPool;
    this.redis = redisClient;
    this.kafka = kafka;
    this.FEED_CACHE_TTL = 3600;      // 1 hour
    this.POST_CACHE_TTL = 86400;     // 24 hours
    this.FEED_SIZE = 1000;
    this.CELEBRITY_THRESHOLD = 10000;
  }

  async createPost(userId, caption, imageUrlOriginal, imageUrlFeed, imageUrlThumb) {
    const [result] = await this.db.query(
      `INSERT INTO posts (user_id, caption, image_url_original, image_url_feed, 
       image_url_thumb, created_at) VALUES (?, ?, ?, ?, ?, NOW())`,
      [userId, caption, imageUrlOriginal, imageUrlFeed, imageUrlThumb]
    );

    const postId = result.insertId;

    // Fanout post to followers
    await this._fanoutPost(userId, postId);

    // Cache post metadata
    const postData = {
      id: postId,
      userId,
      caption,
      likeCount: 0,
      commentCount: 0,
      createdAt: new Date().toISOString()
    };
    await this.redis.setEx(`post:${postId}`, this.POST_CACHE_TTL, JSON.stringify(postData));

    return postId;
  }

  async _fanoutPost(userId, postId) {
    // Check if user is celebrity
    const [rows] = await this.db.query(
      'SELECT followers_count FROM users WHERE id = ?',
      [userId]
    );
    const followersCount = rows[0]?.followers_count || 0;

    if (followersCount < this.CELEBRITY_THRESHOLD) {
      // Regular user: fanout to all followers
      const [followers] = await this.db.query(
        'SELECT follower_id FROM follows WHERE following_id = ?',
        [userId]
      );

      const score = Date.now() / 1000; // unix timestamp
      for (const { follower_id } of followers) {
        // Add post to follower's feed (sorted set)
        await this.redis.zAdd(`feed:${follower_id}`, { score, value: String(postId) });
        // Trim to top 1000
        await this.redis.zRemRangeByRank(`feed:${follower_id}`, this.FEED_SIZE, -1);
        // Invalidate feed cache
        await this.redis.del(`feed_posts:${follower_id}`);
      }
    }
    // Celebrity: don't fanout
  }

  async getFeed(userId, limit = 20, offset = 0) {
    // Check cache first
    const cachedFeed = await this.redis.get(`feed_posts:${userId}`);
    let postIds;

    if (cachedFeed) {
      postIds = JSON.parse(cachedFeed);
    } else {
      // Cache miss: reconstruct feed
      postIds = await this._buildFeed(userId);
      // Cache for 1 hour
      await this.redis.setEx(
        `feed_posts:${userId}`,
        this.FEED_CACHE_TTL,
        JSON.stringify(postIds)
      );
    }

    // Paginate
    const paginatedIds = postIds.slice(offset, offset + limit);

    // Fetch post metadata
    const posts = [];
    for (const postId of paginatedIds) {
      const cached = await this.redis.get(`post:${postId}`);
      if (cached) {
        posts.push(JSON.parse(cached));
      } else {
        // Fetch from DB
        const [rows] = await this.db.query(
          `SELECT id, user_id, caption, like_count, comment_count, 
           image_url_feed, created_at FROM posts WHERE id = ?`,
          [postId]
        );
        if (rows.length > 0) {
          const post = rows[0];
          const postDict = {
            id: post.id,
            userId: post.user_id,
            caption: post.caption,
            likeCount: post.like_count,
            commentCount: post.comment_count,
            imageUrl: post.image_url_feed,
            createdAt: post.created_at.toISOString()
          };
          await this.redis.setEx(`post:${postId}`, this.POST_CACHE_TTL, JSON.stringify(postDict));
          posts.push(postDict);
        }
      }
    }

    return posts;
  }

  async _buildFeed(userId) {
    // Get followed users
    const [following] = await this.db.query(
      'SELECT following_id FROM follows WHERE follower_id = ? LIMIT 5000',
      [userId]
    );

    if (following.length === 0) return [];

    const followingIds = following.map(f => f.following_id);
    const placeholders = followingIds.map(() => '?').join(',');

    // Fetch posts from followed users (chronological)
    const [posts] = await this.db.query(
      `SELECT id FROM posts WHERE user_id IN (${placeholders}) 
       ORDER BY created_at DESC LIMIT 1000`,
      followingIds
    );

    return posts.map(p => p.id);
  }

  async likePost(userId, postId) {
    try {
      await this.db.query(
        'INSERT INTO likes (post_id, user_id, created_at) VALUES (?, ?, NOW())',
        [postId, userId]
      );

      // Async: increment like count
      await this.redis.incr(`post_likes:${postId}`);

      // Get post owner
      const [rows] = await this.db.query('SELECT user_id FROM posts WHERE id = ?', [postId]);
      const postOwner = rows[0]?.user_id;

      // Publish to Kafka
      await this.kafka.producer.send({
        topic: 'likes',
        messages: [{
          value: JSON.stringify({
            postId,
            likerId: userId,
            postOwnerId: postOwner,
            timestamp: new Date().toISOString()
          })
        }]
      });
    } catch (e) {
      // Duplicate like
      console.error(e);
    }
  }

  async commentPost(userId, postId, content) {
    const [result] = await this.db.query(
      'INSERT INTO comments (post_id, user_id, content, created_at) VALUES (?, ?, ?, NOW())',
      [postId, userId, content]
    );
    const commentId = result.insertId;

    // Increment comment count
    await this.redis.incr(`post_comments:${postId}`);

    // Get post owner
    const [rows] = await this.db.query('SELECT user_id FROM posts WHERE id = ?', [postId]);
    const postOwner = rows[0]?.user_id;

    // Publish event
    await this.kafka.producer.send({
      topic: 'comments',
      messages: [{
        value: JSON.stringify({
          postId,
          commenterId: userId,
          commentId,
          postOwnerId: postOwner,
          timestamp: new Date().toISOString()
        })
      }]
    });

    return commentId;
  }

  async followUser(followerId, followingId) {
    try {
      await this.db.query(
        'INSERT INTO follows (follower_id, following_id, created_at) VALUES (?, ?, NOW())',
        [followerId, followingId]
      );

      // Update follower counts
      await this.db.query(
        'UPDATE users SET followers_count = followers_count + 1 WHERE id = ?',
        [followingId]
      );
      await this.db.query(
        'UPDATE users SET following_count = following_count + 1 WHERE id = ?',
        [followerId]
      );

      // Invalidate caches
      await Promise.all([
        this.redis.del(`user:${followerId}`),
        this.redis.del(`user:${followingId}`),
        this.redis.del(`feed_posts:${followerId}`)
      ]);

      // Publish notification
      await this.kafka.producer.send({
        topic: 'follows',
        messages: [{
          value: JSON.stringify({
            followerId,
            followingId,
            timestamp: new Date().toISOString()
          })
        }]
      });
    } catch (e) {
      // Duplicate follow
      console.error(e);
    }
  }
}

module.exports = Instagram;

