// Zero-downtime sharding migration: dual-write pattern
type Writer interface {
  Write(ctx context.Context, key string, value interface{}) error
}

type DualWriter struct {
  primaryDB   *sql.DB
  shardedDB   *ShardedDB
  validateFn  func(old, new interface{}) bool
}

func (dw *DualWriter) Write(ctx context.Context, key string, value interface{}) error {
  // Write to primary (legacy)
  primaryErr := dw.primaryDB.WriteRecord(ctx, key, value)
  if primaryErr != nil {
    return primaryErr // Primary must succeed
  }

  // Shadow write to sharded (async, with logging)
  go func() {
    shardErr := dw.shardedDB.Write(ctx, key, value)
    if shardErr != nil {
      log.Warn("sharded write failed", "key", key, "err", shardErr)
      // Log discrepancy for investigation
      dw.logDataDivergence(key, primaryErr, shardErr)
    }
  }()

  return nil
}

// Gradual migration: route percentage of reads to sharded DB
type MigrationRouter struct {
  primaryDB  *sql.DB
  shardedDB  *ShardedDB
  percentage int // 0-100
}

func (mr *MigrationRouter) Read(ctx context.Context, key string) (interface{}, error) {
  // Route based on percentage
  if rand.Intn(100) < mr.percentage {
    return mr.shardedDB.Read(ctx, key) // Read from sharded
  }
  return mr.primaryDB.Read(ctx, key) // Read from primary
}

// Gradual increase over time
func (mr *MigrationRouter) IncrementPercentage(delta int) {
  mr.percentage = (mr.percentage + delta) % 101
  log.Info("migration progress", "percentage", mr.percentage)
}

