const redis = require('redis');
const client = redis.createClient();

class CachedDatabase {
  async getUserProfile(userId) {
    // Check cache first
    const cached = await client.get(`user:${userId}`);
    if (cached) {
      return JSON.parse(cached);
    }

    // Cache miss: fetch from DB
    const profile = await db.query(
      'SELECT * FROM users WHERE id = ?', [userId]
    );

    // Store in cache with TTL of 1 hour
    await client.setex(
      `user:${userId}`,
      3600, // TTL in seconds
      JSON.stringify(profile)
    );

    return profile;
  }

  async updateUserProfile(userId, updates) {
    // Write to DB
    await db.query(
      'UPDATE users SET ? WHERE id = ?', [updates, userId]
    );

    // Invalidate cache immediately on write
    await client.del(`user:${userId}`);

    // Also invalidate dependent caches
    await client.del(`user_feed:${userId}`);
    await client.del(`user_stats:${userId}`);
  }
}

// Sharding function: deterministic partition
function getShardId(userId, numShards) {
  // Hash consistently to same shard
  const hash = require('crypto')
    .createHash('md5')
    .update(userId.toString())
    .digest('hex');
  const hashValue = parseInt(hash, 16);
  return hashValue % numShards; // Maps 0 to (numShards-1)
}

const shardId = getShardId(userId, 4); // 4 shards
const connection = shardedDB.getConnection(shardId);

function reverseString(s) {
    let left = 0, right = s.length - 1;
    while (left < right) {
        [s[left], s[right]] = [s[right], s[left]];
        left++; right--;
    }
    return s;
}

