fn max_subarray(nums: &[i32], k: usize) -> i32 {
    let mut window_sum: i32 = nums[..k].iter().sum();
    let mut max_sum = window_sum;
    for i in k..nums.len() {
        window_sum += nums[i] - nums[i - k];
        max_sum = max_sum.max(window_sum);
    }
    max_sum
}

