use std::sync::{Arc, Mutex};
use std::thread;
use std::time::Duration;

pub struct Debounce {
    delay: Duration,
    handle: Arc<Mutex<Option<thread::JoinHandle<()>>>>,
}

impl Debounce {
    pub fn new(delay: Duration) -> Self {
        Self { delay, handle: Arc::new(Mutex::new(None)) }
    }

    pub fn call<F: FnOnce() + Send + 'static>(&self, f: F) {
        let delay = self.delay;
        // simplified: spawn a new thread per call (production: use tokio or a timer crate)
        thread::spawn(move || {
            thread::sleep(delay);
            f();
        });
    }
}

