// Node.js + Prometheus + Winston logging
const prometheus = require('prom-client');
const winston = require('winston');
const express = require('express');
const { v4: uuidv4 } = require('uuid');
const { AsyncLocalStorage } = require('async_hooks');

// Metrics
const httpRequests = new prometheus.Counter({
  name: 'http_requests_total',
  help: 'Total HTTP requests',
  labelNames: ['method', 'endpoint', 'status']
});

const httpLatency = new prometheus.Histogram({
  name: 'http_request_duration_seconds',
  help: 'Request latency',
  buckets: [0.1, 0.5, 1.0, 2.0]
});

const dbConnections = new prometheus.Gauge({
  name: 'db_connections_active',
  help: 'Active DB connections'
});

// Distributed tracing context
const traceIdStorage = new AsyncLocalStorage();

// Structured logging with Winston
const logger = winston.createLogger({
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.printf(info => {
      const traceId = traceIdStorage.getStore();
      return JSON.stringify({
        timestamp: info.timestamp,
        level: info.level,
        message: info.message,
        trace_id: traceId,
        ...info
      });
    })
  ),
  transports: [new winston.transports.Console()]
});

const app = express();

// Prometheus metrics endpoint
app.get('/metrics', (req, res) => {
  res.set('Content-Type', prometheus.register.contentType);
  res.end(prometheus.register.metrics());
});

// Trace ID middleware
app.use((req, res, next) => {
  const traceId = req.headers['x-trace-id'] || uuidv4();
  res.setHeader('X-Trace-ID', traceId);

  traceIdStorage.run(traceId, () => {
    logger.info(`Request started: ${req.method} ${req.path}`);
    req.startTime = Date.now();
    next();
  });
});

// Request timing and metrics middleware
app.use((req, res, next) => {
  res.on('finish', () => {
    const duration = (Date.now() - req.startTime) / 1000;
    httpRequests.labels(req.method, req.path, res.statusCode).inc();
    httpLatency.observe(duration);

    const traceId = traceIdStorage.getStore();
    logger.info(`Request completed: ${res.statusCode} in ${duration.toFixed(2)}s`);
  });
  next();
});

app.post('/checkout', async (req, res) => {
  const traceId = traceIdStorage.getStore();
  logger.info('Checkout started');

  dbConnections.inc();
  try {
    // Simulate DB query
    await new Promise(resolve => setTimeout(resolve, 200));
    logger.info('DB query completed');
    res.json({ status: 'success' });
  } catch (err) {
    logger.error(`Checkout failed: ${err.message}`);
    res.status(500).json({ error: err.message });
  } finally {
    dbConnections.dec();
  }
});

app.listen(3000, () => {
  logger.info('Server started on port 3000');
});

