use actix_web::{web, App, HttpServer, HttpRequest, HttpResponse, middleware};
use prometheus::{Counter, Histogram, IntGauge, Registry, TextEncoder, Encoder};
use std::sync::Arc;
use std::time::Instant;
use uuid::Uuid;
use serde_json::json;
use log::info;
use tokio::sync::RwLock;

struct Metrics {
    http_requests_total: Counter,
    http_request_duration_seconds: Histogram,
    db_connections_active: IntGauge,
}

impl Metrics {
    fn new() -> Self {
        let registry = Registry::new();
        Self {
            http_requests_total: Counter::new(
                "http_requests_total",
                "Total HTTP requests"
            ).unwrap(),
            http_request_duration_seconds: Histogram::with_opts(
                prometheus::HistogramOpts::new(
                    "http_request_duration_seconds",
                    "Request latency"
                ).buckets(vec![0.1, 0.5, 1.0, 2.0])
            ).unwrap(),
            db_connections_active: IntGauge::new(
                "db_connections_active",
                "Active DB connections"
            ).unwrap(),
        }
    }
}

struct AppState {
    metrics: Arc<Metrics>,
}

// Trace ID context key
const TRACE_ID_HEADER: &str = "X-Trace-ID";

// Middleware to add trace ID and measure latency
async fn metrics_middleware(
    req: HttpRequest,
    srv: web::Data<AppState>,
    next: actix_web::dev::Next,
) -> actix_web::Result<actix_web::dev::ServiceResponse> {
    let trace_id = req
        .headers()
        .get(TRACE_ID_HEADER)
        .and_then(|h| h.to_str().ok())
        .unwrap_or(&Uuid::new_v4().to_string())
        .to_string();

    info!("request started: {} {}", req.method(), req.path());
    let start = Instant::now();

    let mut response = next.call(req).await?;
    let duration = start.elapsed().as_secs_f64();

    srv.metrics.http_request_duration_seconds.observe(duration);
    response.headers_mut().insert(
        actix_web::http::header::HeaderName::from_static(TRACE_ID_HEADER),
        actix_web::http::header::HeaderValue::from_str(&trace_id).unwrap()
    );

    info!("request completed: status={} duration_ms={:.0} trace_id={}",
        response.status(),
        duration * 1000.0,
        trace_id
    );

    Ok(response)
}

// Checkout endpoint
async fn checkout(
    req: HttpRequest,
    state: web::Data<AppState>,
) -> HttpResponse {
    let trace_id = req
        .headers()
        .get(TRACE_ID_HEADER)
        .and_then(|h| h.to_str().ok())
        .unwrap_or("unknown");

    info!("checkout started: trace_id={}", trace_id);

    state.metrics.db_connections_active.inc();

    // Simulate DB query
    tokio::time::sleep(tokio::time::Duration::from_millis(200)).await;
    info!("db query completed: trace_id={}", trace_id);

    state.metrics.db_connections_active.dec();

    state.metrics.http_requests_total.inc();

    HttpResponse::Ok().json(json!({
        "status": "success",
        "trace_id": trace_id
    }))
}

// Health check
async fn health() -> HttpResponse {
    HttpResponse::Ok().body("OK")
}

// Metrics endpoint
async fn metrics(state: web::Data<AppState>) -> HttpResponse {
    let encoder = TextEncoder::new();
    let metric_families = prometheus::gather();
    let mut buffer = Vec::new();
    encoder.encode(&metric_families, &mut buffer).unwrap();

    HttpResponse::Ok()
        .content_type("text/plain; version=0.0.4")
        .body(buffer)
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    env_logger::init_from_env(env_logger::Env::default().default_filter_or("info"));

    let metrics = Arc::new(Metrics::new());
    let state = web::Data::new(AppState {
        metrics: metrics.clone(),
    });

    info!("starting server on 0.0.0.0:8080");

    HttpServer::new(move || {
        App::new()
            .app_data(state.clone())
            .wrap(actix_web::middleware::Logger::default())
            .wrap_fn(metrics_middleware)
            .route("/health", web::get().to(health))
            .route("/metrics", web::get().to(metrics))
            .route("/checkout", web::post().to(checkout))
    })
    .bind("0.0.0.0:8080")?
    .run()
    .await
}

