// Metrics storage
typedef struct {
    long http_requests_total;
    double http_request_duration_ms;
    int db_connections_active;
    time_t last_reset;
} Metrics;

Metrics metrics = {0};
pthread_mutex_t metrics_lock = PTHREAD_MUTEX_INITIALIZER;

// Trace context
typedef struct {
    char trace_id[37];  // UUID4 + null
} TraceContext;

// Generate UUID v4
void generate_trace_id(char *buf) {
    uuid_t uuid;
    uuid_generate(uuid);
    uuid_unparse(uuid, buf);
}

// Get or create trace ID from header
void get_or_create_trace_id(const char *header_value, char *out_trace_id) {
    if (header_value != NULL && strlen(header_value) > 0) {
        strcpy(out_trace_id, header_value);
    } else {
        generate_trace_id(out_trace_id);
    }
}

// Log with trace ID
void log_with_trace(const char *level, const char *trace_id, const char *message) {
    time_t now = time(NULL);
    char timestamp[32];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%dT%H:%M:%SZ", gmtime(&now));

    // JSON structured logging
    printf("{\"%s\":\"%s\",\"level\":\"%s\",\"trace_id\":\"%s\",\"message\":\"%s\"}\n",
           "timestamp", timestamp, level, trace_id, message);
    fflush(stdout);
}

// Record metrics
void record_request_metric(double duration_ms) {
    pthread_mutex_lock(&metrics_lock);
    metrics.http_requests_total++;
    metrics.http_request_duration_ms = duration_ms;
    pthread_mutex_unlock(&metrics_lock);
}

void inc_db_connections(void) {
    pthread_mutex_lock(&metrics_lock);
    metrics.db_connections_active++;
    pthread_mutex_unlock(&metrics_lock);
}

void dec_db_connections(void) {
    pthread_mutex_lock(&metrics_lock);
    metrics.db_connections_active--;
    pthread_mutex_unlock(&metrics_lock);
}

// Prometheus metrics endpoint
void print_metrics(void) {
    pthread_mutex_lock(&metrics_lock);
    printf("# HELP http_requests_total Total HTTP requests\n");
    printf("# TYPE http_requests_total counter\n");
    printf("http_requests_total %ld\n", metrics.http_requests_total);

    printf("# HELP http_request_duration_ms Request latency\n");
    printf("# TYPE http_request_duration_ms gauge\n");
    printf("http_request_duration_ms %.2f\n", metrics.http_request_duration_ms);

    printf("# HELP db_connections_active Active DB connections\n");
    printf("# TYPE db_connections_active gauge\n");
    printf("db_connections_active %d\n", metrics.db_connections_active);
    pthread_mutex_unlock(&metrics_lock);
}

// Simulated HTTP handler
int handle_checkout(const char *trace_id) {
    clock_t start = clock();

    log_with_trace("INFO", trace_id, "checkout started");

    inc_db_connections();

    // Simulate DB query (100-200ms)
    usleep((100 + (rand() % 100)) * 1000);

    log_with_trace("INFO", trace_id, "db query completed");

    dec_db_connections();

    clock_t end = clock();
    double duration_ms = ((double)(end - start) / CLOCKS_PER_SEC) * 1000.0;
    record_request_metric(duration_ms);

    log_with_trace("INFO", trace_id, "checkout completed");

    return 200;  // HTTP 200 OK
}

// HTTP server simulation (simplified)
int main(int argc, char *argv[]) {
    srand(time(NULL));

    // Simulate multiple requests
    for (int i = 0; i < 5; i++) {
        char trace_id[37];
        generate_trace_id(trace_id);

        log_with_trace("INFO", trace_id, "request started");

        int status = handle_checkout(trace_id);

        log_with_trace("INFO", trace_id, "request completed");

        sleep(1);  // Simulate request spacing
    }

    // Print metrics in Prometheus format
    printf("\n--- Prometheus Metrics ---\n");
    print_metrics();

    return 0;
}

