#include <iostream>
#include <vector>
#include <map>
#include <string>
#include <fstream>
#include <sstream>
#include <nlohmann/json.hpp>

using json = nlohmann::json;

// Parse CSV to JSON array
json csvToJson(const std::string& csvData) {
    std::istringstream stream(csvData);
    std::string line;
    std::vector<std::string> headers;
    json result = json::array();
    bool isHeader = true;

    while (std::getline(stream, line)) {
        std::istringstream lineStream(line);
        std::string cell;
        std::vector<std::string> row;

        while (std::getline(lineStream, cell, ',')) {
            row.push_back(cell);
        }

        if (isHeader) {
            headers = row;
            isHeader = false;
        } else {
            json obj = json::object();
            for (size_t i = 0; i < headers.size(); ++i) {
                obj[headers[i]] = row[i];
            }
            result.push_back(obj);
        }
    }

    return result;
}

int main() {
    std::string csvData = "name,email,age\n"
                         "john,john@example.com,25\n"
                         "jane,jane@example.com,28";

    json jsonResult = csvToJson(csvData);
    std::cout << jsonResult.dump(2) << std::endl;

    // Output: [{"age": "25", "email": "john@example.com", "name": "john"}, ...]

    return 0;
}

// Compile: g++ -std=c++17 csv_to_json.cpp -o csv_to_json
// Requires nlohmann/json header library

