// Example: Custom Streamlit Component wrapper

import Streamlit from "streamlit-component-lib"
import React from "react"

const StreamlitSnowflakeComponent = (props) => {
  const [data, setData] = React.useState([])
  const [loading, setLoading] = React.useState(false)

  React.useEffect(() => {
    const fetchData = async () => {
      setLoading(true)
      try {
        const response = await fetch('/api/snowflake/query', {
          method: 'POST',
          body: JSON.stringify({ query: props.query })
        })
        const result = await response.json()
        setData(result)
        Streamlit.setComponentValue(result)
      } finally {
        setLoading(false)
      }
    }
    fetchData()
  }, [props.query])

  return (
    <div>
      {loading ? <p>Loading...</p> : <table>{/* render data */}</table>}
    </div>
  )
}

export default Streamlit.withStreamlitConnection(StreamlitSnowflakeComponent)

