// Go example: REST API backend for Streamlit to query Snowflake
package main

import (
    "database/sql"
    "encoding/json"
    "fmt"
    "log"
    "net/http"
    _ "github.com/snowflakedb/gosnowflake"
)

type QueryRequest struct {
    Query string `json:"query"`
}

type QueryResponse struct {
    Data  []map[string]interface{} `json:"data"`
    Error string                   `json:"error,omitempty"`
}

func querySnowflake(w http.ResponseWriter, r *http.Request) {
    if r.Method != http.MethodPost {
        http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
        return
    }

    var req QueryRequest
    if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
        http.Error(w, "Invalid request", http.StatusBadRequest)
        return
    }

    dsn := fmt.Sprintf("%s:%s@tcp(%s:443)/snowflake?warehouse=%s&database=%s",
        os.Getenv("SNOWFLAKE_USER"),
        os.Getenv("SNOWFLAKE_PASSWORD"),
        os.Getenv("SNOWFLAKE_ACCOUNT"),
        os.Getenv("SNOWFLAKE_WAREHOUSE"),
        os.Getenv("SNOWFLAKE_DATABASE"),
    )

    db, err := sql.Open("snowflake", dsn)
    if err != nil {
        respond(w, QueryResponse{Error: err.Error()}, http.StatusInternalServerError)
        return
    }
    defer db.Close()

    rows, err := db.Query(req.Query)
    if err != nil {
        respond(w, QueryResponse{Error: err.Error()}, http.StatusBadRequest)
        return
    }
    defer rows.Close()

    cols, _ := rows.Columns()
    var data []map[string]interface{}

    for rows.Next() {
        values := make([]interface{}, len(cols))
        valuePtrs := make([]interface{}, len(cols))
        for i := range cols {
            valuePtrs[i] = &values[i]
        }
        rows.Scan(valuePtrs...)
        entry := make(map[string]interface{})
        for i, col := range cols {
            entry[col] = values[i]
        }
        data = append(data, entry)
    }

    respond(w, QueryResponse{Data: data}, http.StatusOK)
}

func respond(w http.ResponseWriter, resp QueryResponse, status int) {
    w.Header().Set("Content-Type", "application/json")
    w.WriteHeader(status)
    json.NewEncoder(w).Encode(resp)
}

func main() {
    http.HandleFunc("/api/query", querySnowflake)
    log.Fatal(http.ListenAndServe(":8080", nil))
}

