package main

import (
	"context"
	"fmt"
	appsv1 "k8s.io/api/apps/v1"
	corev1 "k8s.io/api/core/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"
)

// CRD spec for Database
type DatabaseSpec struct {
	Version     string            `json:\"version\"`
	Replicas    int32             `json:\"replicas\"`
	StorageSize string            `json:\"storageSize\"`
	Config      map[string]string `json:\"config\"`
}

// Reconciliation: when Database CRD created, create StatefulSet + PVCs
func reconcileDatabase(clientset *kubernetes.Clientset, dbName, namespace string, spec DatabaseSpec) error {
	// Create StatefulSet
	ss := &appsv1.StatefulSet{
		ObjectMeta: metav1.ObjectMeta{
			Name:      fmt.Sprintf(\"postgres-%s\", dbName),
			Namespace: namespace,
		},
		Spec: appsv1.StatefulSetSpec{
			ServiceName: fmt.Sprintf(\"postgres-%s\", dbName),
			Replicas:    &spec.Replicas,
			Selector: &metav1.LabelSelector{
				MatchLabels: map[string]string{\"db\": dbName},
			},
			Template: corev1.PodTemplateSpec{
				Metadata: metav1.ObjectMeta{
					Labels: map[string]string{\"db\": dbName},
				},
				Spec: corev1.PodSpec{
					Containers: []corev1.Container{{
						Name:  \"postgres\",
						Image: fmt.Sprintf(\"postgres:%s\", spec.Version),
					}},
				},
			},
		},
	}

	_, err := clientset.AppsV1().StatefulSets(namespace).Create(context.Background(), ss, metav1.CreateOptions{})
	return err
}
